	return 0 < sep_len && chk_len >= sep_len && *chk_str == *sep_str && !memcmp(chk_str + 1, sep_str + 1, sep_len - 1);
}

static size_t check_sep(php_http_params_state_t *state, php_http_params_token_t **separators)
{
